package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.CodeEnum;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.SqlParameterValue;
import org.springframework.jdbc.support.rowset.SqlRowSet;
import org.springframework.transaction.annotation.Transactional;

import javax.sql.DataSource;
import java.sql.Types;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collection;
import java.util.List;

@Transactional
public class StandaardVrijeBrandweerService implements VrijeBrandweerService {

    @Autowired
    private DataSource dataSource;

    private static final Hoedanigheid[] HOEDANIGHEDEN_VRIJWILLIGE_BRANDWEER =
            {Hoedanigheid.VRIJWILLIGE_BRANDWEER, Hoedanigheid.VRIJWILLIGE_BRANDWEER_ERKENTELIJKHEIDSPREMIE,
                    Hoedanigheid.DIENST_100_MET_CUMUL_VRIJWILLIGE_BRANDWEER, Hoedanigheid.DIENST_100_2015_MET_CUMUL_VRIJWILLIGE_BRANDWEER,
                    Hoedanigheid.DIENST_100_2015_ZONDER_CUMUL_VRIJWILLIGE_BRANDWEER};

    private static final RekenBedragType[] BV_BEDRAG_TYPES = {RekenBedragType.BEDRIJFSVOORHEFFING, RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL};

    private static final String GET_KEY_OTHER_SQL = "select sum(rb.bedrag) from rekenhoofd rh" + " join opdracht_master om on om.id=rh.opdrachtid"
            + " join rekenlijn rl on rl.rekenhoofdid=rh.id " + " join rekenbedrag rb on rl.id=rb.rekenlijnid"
            + " where bedragtypectid=? and om.persoonId=? and fiscaal_jaar=? and rh.begindatum!=?" + " and rl.regimebvctid not in " + toCtIdString(
            BvTools.getUitgeslotenRegimesVoorBbVrijwilligeBrandweer()) + " and rh.hoedanigheidctid in " + toCtIdString(
            HOEDANIGHEDEN_VRIJWILLIGE_BRANDWEER);

    private static final String GET_KEY_OTHER_BV_SQL = "select sum(rb.bedrag) from rekenhoofd rh" + " join opdracht_master om on om.id=rh.opdrachtid"
            + " join rekenlijn rl on rl.rekenhoofdid=rh.id " + " join rekenbedrag rb on rl.id=rb.rekenlijnid" + " where bedragtypectid in "
            + toCtIdString(BV_BEDRAG_TYPES)
            + " and om.persoonId=? and fiscaal_jaar=? and rh.begindatum!=? and rl.regimebvctid = ? and rh.hoedanigheidctid in " + toCtIdString(
            HOEDANIGHEDEN_VRIJWILLIGE_BRANDWEER);

    @InitializeAdmin
    @Override
    public Money getBedrijfsvoorheffingOther(Admin admin, Persoon persoon, int fiscaalJaar, LocalDate huidigeBegindatum) {
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[4];
        args[0] = new SqlParameterValue(Types.INTEGER, persoon.getId());
        args[1] = new SqlParameterValue(Types.INTEGER, fiscaalJaar);
        args[2] = new SqlParameterValue(Types.DATE, new java.sql.Date(huidigeBegindatum.toDate().getTime()));
        args[3] = new SqlParameterValue(Types.INTEGER, LnedefRegBv.VD_BV_10_BZ___VB.getId());
        String resultaat = jdbc.queryForObject(GET_KEY_OTHER_BV_SQL, args, String.class);

        Money result = Money.ZERO;
        if (resultaat != null) {
            result = new Money(resultaat);
        }
        return result;
    }

    @InitializeAdmin
    @Override
    public Money getBelastbaarOther(Admin admin, Persoon persoon, int fiscaalJaar, LocalDate huidigeBegindatum) {
        return executeQuery(persoon, RekenBbKey.BELASTBAAR_KEY, fiscaalJaar, huidigeBegindatum);
    }

    @InitializeAdmin
    @Override
    public Money getRuwBelastbaarOther(Admin admin, Persoon persoon, int fiscaalJaar, LocalDate huidigeBegindatum) {
        return executeQuery(persoon, RekenBbKey.RUW_BELASTBAAR_KEY, fiscaalJaar, huidigeBegindatum);
    }

    @InitializeAdmin
    @Override
    public Money getBelastbaarVrijstelling(Admin admin, Persoon persoon, int fiscaalJaar, LocalDate huidigeBegindatum) {
        return executeQuery(persoon, RekenBbKey.VRIJSTELLING_BELASTBAAR_KEY, fiscaalJaar, huidigeBegindatum);
    }

    private Money executeQuery(Persoon persoon, MoneyKey moneyKey, Integer fiscaalJaar, LocalDate huidigeBegindatum) {
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[4];
        args[0] = new SqlParameterValue(Types.VARCHAR, moneyKey.toEnumType().getId());
        args[1] = new SqlParameterValue(Types.INTEGER, persoon.getId());
        args[2] = new SqlParameterValue(Types.INTEGER, fiscaalJaar);
        args[3] = new SqlParameterValue(Types.DATE, new java.sql.Date(huidigeBegindatum.toDate().getTime()));
        String resultaat = jdbc.queryForObject(GET_KEY_OTHER_SQL, args, String.class);

        Money result = Money.ZERO;
        if (resultaat != null) {
            result = new Money(resultaat);
        }
        return result;
    }

    private static final String QUERY_INFO_VRIJSTELLING_BELASTBAAR_FISCAAL_JAAR =
            "select om.persoonid, om.id, om.werkgeverid, om.opdrachtnr, rh.begindatum, rh.fiscaal_jaar, sum(case when bedragtypectid = "
                    + RekenBedragType.BELASTBAAR.getId() + " then bedrag else 0 end) as belastbaar,sum(case when bedragtypectid = "
                    + RekenBedragType.VRIJSTELLING_BELASTBAAR.getId() + " then bedrag else 0 end) as vrijstelling from rekenhoofd rh"
                    + " left join rekenlijn rl on rh.id=rl.rekenhoofdid" + " left join rekenbedrag rb on rb.rekenlijnid=rl.id"
                    + " left join opdracht_master om on rh.opdrachtid=om.id" + " where bedragtypectid in (" + RekenBedragType.BELASTBAAR.getId() + ","
                    + RekenBedragType.VRIJSTELLING_BELASTBAAR.getId() + ") and persoonid=? and fiscaal_jaar=? and rh.hoedanigheidctid in " + toCtIdString(
                    HOEDANIGHEDEN_VRIJWILLIGE_BRANDWEER) + " and rl.regimebvctid=" + LnedefRegBv.VD_BV_10_BZ___VB.getId()
                    + " group by om.persoonid,om.id,om.werkgeverid,om.opdrachtnr,rh.begindatum,rh.fiscaal_jaar";

    @Override
    @InitializeAdmin
    public List<InfoVrijstellingBelastbaar> findInfoMaandenMetVrijstellingInDitFiscaalJaar(Admin admin, int persoonId, int fiscaalJaar) {
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);
        Object[] args = new Object[2];
        args[0] = new SqlParameterValue(Types.INTEGER, persoonId);
        args[1] = new SqlParameterValue(Types.INTEGER, fiscaalJaar);
        SqlRowSet rowSet = jdbc.queryForRowSet(QUERY_INFO_VRIJSTELLING_BELASTBAAR_FISCAAL_JAAR, args);
        List<InfoVrijstellingBelastbaar> infos = new ArrayList<>();
        while (rowSet.next()) {
            InfoVrijstellingBelastbaar info = new InfoVrijstellingBelastbaar();
            info.setPersoonId(rowSet.getInt(1));
            info.setOpdrachtId(rowSet.getInt(2));
            info.setWerkgeverId(rowSet.getInt(3));
            info.setOpdrachtNr(rowSet.getInt(4));
            info.setBeginDatum(LocalDate.fromDateFields(rowSet.getDate(5)));
            info.setFiscaalJaar(rowSet.getInt(6));
            info.setBelastbaar(new Money(rowSet.getBigDecimal(7)));
            info.setVrijstelling(new Money(rowSet.getBigDecimal(8)));
            infos.add(info);
        }
        return infos;
    }

    private static String toCtIdString(CodeEnum[] codeEnums) {
        return toCtIdString(Arrays.asList(codeEnums));
    }

    private static <T extends CodeEnum> String toCtIdString(Collection<T> codeEnums) {
        StringBuilder ctIdString = new StringBuilder("(");
        boolean first = true;
        for (T codeEnum : codeEnums) {
            if (first) {
                first = false;
            } else {
                ctIdString.append(",");
            }
            ctIdString.append(codeEnum.getId());
        }
        ctIdString.append(")");
        return ctIdString.toString();
    }
}
